import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.next();

        // Assume that the buffer size for storing the name is limited to 10 characters
        char[] buffer = new char[10];

        // Copy a safe amount of characters from user input into the buffer
        int copyLength = Math.min(input.length(), buffer.length);
        for (int i = 0; i < copyLength; i++) {
            buffer[i] = input.charAt(i);
        }

        // Display the contents of the buffer
        System.out.println("Name: " + new String(buffer));
    }
}

